/**
 * useSpatialIndex - Hook for managing a spatial index
 *
 * Creates and maintains a spatial index for tasks.
 * The index is rebuilt when tasks change.
 *
 * Usage:
 * ```tsx
 * const spatialIndex = useSpatialIndex(tasks);
 * const visibleIds = spatialIndex.queryViewport(viewportBounds);
 * ```
 *
 * @see PERF-002 Phase 3
 */

import { useMemo, useRef, useEffect } from 'react';
import type { TaskRender } from '../data/types';
import { DEFAULT_VIEW_CONFIG } from '../data/types';
import type { ISpatialIndex } from './types';
import { tasksToSpatialItems } from './types';
import { SimpleSpatialIndex } from './SimpleSpatialIndex';

const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;

/**
 * Hook that creates and manages a spatial index for tasks.
 *
 * The index is automatically rebuilt when tasks change.
 * Uses SimpleSpatialIndex by default (O(n) queries).
 * Will be upgraded to RBush in STATE-ARCH-001.Phase2.
 *
 * @param tasks - Array of tasks to index
 * @returns Spatial index instance
 */
export function useSpatialIndex(tasks: TaskRender[]): ISpatialIndex {
  // Keep a stable reference to the index
  const indexRef = useRef<ISpatialIndex | null>(null);

  // Create index if not exists
  if (!indexRef.current) {
    indexRef.current = new SimpleSpatialIndex();
  }

  // Rebuild index when tasks change
  useEffect(() => {
    if (indexRef.current && tasks.length > 0) {
      const items = tasksToSpatialItems(tasks, pxPerDay, pxPerTrain);
      indexRef.current.load(items);

      // Log stats in development
      if (import.meta.env.DEV) {
        const stats = indexRef.current.getStats();
        console.log(`[SpatialIndex] Loaded ${stats.itemCount} items in ${stats.lastBuildTimeMs?.toFixed(2)}ms`);
      }
    }
  }, [tasks]);

  return indexRef.current;
}

/**
 * Hook that queries visible task IDs from a spatial index.
 *
 * @param spatialIndex - Spatial index to query
 * @param viewportBounds - Current viewport bounds
 * @param padding - Extra padding around viewport
 * @returns Set of visible task IDs
 */
export function useVisibleTaskIds(
  spatialIndex: ISpatialIndex | null,
  viewportBounds: { minX: number; maxX: number; minY: number; maxY: number } | null,
  padding: number = 50
): Set<string> {
  return useMemo(() => {
    if (!spatialIndex || !viewportBounds) {
      return new Set<string>();
    }

    const paddedBounds = {
      minX: viewportBounds.minX - padding,
      maxX: viewportBounds.maxX + padding,
      minY: viewportBounds.minY - padding,
      maxY: viewportBounds.maxY + padding,
    };

    const visibleIds = spatialIndex.queryViewport(paddedBounds);

    // Log query stats in development
    if (import.meta.env.DEV) {
      const stats = spatialIndex.getStats();
      if (stats.lastQueryTimeMs !== undefined) {
        console.log(
          `[SpatialIndex] Query returned ${stats.lastQueryResultCount} items in ${stats.lastQueryTimeMs.toFixed(2)}ms`
        );
      }
    }

    return new Set(visibleIds);
  }, [spatialIndex, viewportBounds, padding]);
}

